.log-container {
  font-family: "Inter", system-ui, sans-serif;
  color: #1a1a1a;
  background: #fff;
  padding: 8px;
  border-radius: 10px;
}

.date-group {
  margin-bottom: 24px;
}

.date-separator {
  display: flex;
  align-items: center;
  justify-content: center;
  color: #9ca3af;
  font-size: 13px;
  margin: 10px 0 16px;
  gap: 10px;
}

.date-separator hr {
  flex: 1;
  border: none;
  border-top: 1px solid #e5e7eb;
}

.log-card {
  margin-bottom: 30px;
}

.log-header {
  display: flex;
  flex-direction: column;
  padding: 10px 16px 4px 16px;
  font-size: 12px;
  color: #555;
}

.log-user {
  font-weight: 700;
  color: #0a3069;
  margin-top: 2px;
}

.log-box {
  border-radius: 8px;
  overflow: hidden;
  margin: 4px 8px;
  border: 1px solid #e5e7eb;
}

.log-box-header {
  background-color: #0a3069;
  color: #fff;
  padding: 8px 12px;
  font-weight: 600;
  font-size: 13px;
  display: flex;
  align-items: center;
  cursor: default;
}

.log-box-header.collapsible {
  cursor: pointer;
}

.toggle-arrow {
  transition: transform 0.3s ease;
  margin-right: 8px;
}

.toggle-arrow.closed {
  transform: rotate(-90deg);
}

.log-content {
  overflow: hidden;
  max-height: 0;
  opacity: 0;
  transition: all 0.4s ease;
}

.log-content.open {
  max-height: 800px;
  opacity: 1;
}

.log-section {
  background-color: #e5e7eb;
  padding: 6px 12px;
  font-weight: 500;
  font-size: 13px;
  color: #1a1a1a;
}

.log-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 8px 12px;
  background-color: #fff;
}

.log-row:hover {
  background: #f7f7f7;
}

.log-label {
  font-size: 14px;
  width: 36%;
  text-align: left;
}

.log-values {
  font-size: 14px;
  font-weight: 600;
  width: 27%;
  text-align: right;
  word-break: break-word;
}

.old-value {
  color: #444;
}

.arrow {
  margin: 0 4px;
  color: #333;
  font-weight: 500;
}

.new-value {
  color: #000;
}

.log-comment {
  padding: 10px 16px 12px 16px;
  background: #fff;
  font-size: 13px;
  color: #333;
  border-radius: 8px;
  margin: 4px 8px;
  border: 1px solid #e5e7eb;
}

.no-changes {
  background-color: #f5f5f5;
  color: #555;
  padding: 10px 14px;
  border-radius: 8px;
  text-align: center;
  font-size: 14px;
  font-weight: 500;
  margin-top: 8px;
}

