import React, { useState } from "https://esm.sh/react@18.2.0";
import ReactDOM from "https://esm.sh/react-dom@18.2.0";

function ChangeLogCard({ log }) {
  const [isOpen, setIsOpen] = useState(true);
  const hasDetails = log.action_type === "Change";

  const valueChanged = log.old_value !== log.new_value;
  const oldDisplay = valueChanged
    ? `${log.old_charge}; ${log.old_value}`
    : log.old_charge;
  const newDisplay = valueChanged
    ? `${log.new_charge}; ${log.new_value}`
    : log.new_charge;

  return (
    <div className="log-card">
      {/* Header */}
      <div className="log-header">
        <div className="log-date-time">
          {new Date(log.created_at).toLocaleTimeString("en-US", {
            hour: "2-digit",
            minute: "2-digit",
          })}
        </div>
        <div className="log-user">{log.user_name || "System"}</div>
      </div>

      {/* Log Box */}
      <div className="log-box">
        <div
          className={`log-box-header ${hasDetails ? "collapsible" : ""}`}
          onClick={() => hasDetails && setIsOpen(!isOpen)}
        >
          {hasDetails ? (
            <div className={`toggle-arrow ${isOpen ? "open" : "closed"}`}>▼</div>
          ) : (
            <div className="toggle-arrow disabled">+</div>
          )}
          <span className="log-title">
            {log.utility_type} | MID {log.meter_id} | SAID {log.service_account_id} | Rate Plan{" "}
            {log.rate_plan}
          </span>
        </div>

        {/* Collapsible Content */}
        {hasDetails && (
          <div className={`log-content ${isOpen ? "open" : "closed"}`}>
            <div className="log-section">
              {valueChanged ? "Usage Charges" : "Other Charges"}
            </div>

            <div className="log-row">
              <div className="log-label">
                {valueChanged
                  ? `${log.new_value}: Label, Charge`
                  : `${log.new_value}: Charge`}
              </div>
              <div className="log-values old-value">{oldDisplay}</div>
              <div className="arrow">→</div>
              <div className="log-values new-value">{newDisplay}</div>
            </div>
          </div>
        )}
      </div>

      {/* Comment always visible */}
      <div className="log-comment">
        <b>Comment</b>&nbsp;{log.comment}
      </div>
    </div>
  );
}

function App() {
  const data = appsmith.model?.data || [];

  // Sort ascending by date
  const sorted = [...data].sort(
    (a, b) => new Date(a.created_at) - new Date(b.created_at)
  );

  // Group by date
  const grouped = sorted.reduce((acc, log) => {
    const date = new Date(log.created_at).toLocaleDateString("en-US");
    if (!acc[date]) acc[date] = [];
    acc[date].push(log);
    return acc;
  }, {});

  const dates = Object.keys(grouped);

  return (
    <div className="log-container">
      {data.length === 0 ? (
        <div className="no-changes">No changes on the bill</div>
      ) : (
        dates.map((date, i) => (
          <div key={i} className="date-group">
            <div className="date-separator">
              <hr />
              <span>{date}</span>
              <hr />
            </div>
            {grouped[date].map((log, idx) => (
              <ChangeLogCard key={idx} log={log} />
            ))}
          </div>
        ))
      )}
    </div>
  );
}

appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
